var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"咳……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카!","JPN":"マブカ！","ENG":"Mavka!","TWN":"瑪卡！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"제길, 끝도 없이 튀어나오는군!","JPN":"くそ、きりがないぞ！","ENG":"Dammit. They're popping out from everywhere!","TWN":"該死，根本沒完沒了！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아저씨! 위험해요!","JPN":"おじさん、危ない！","ENG":"Boris! Look out!","TWN":"大叔！危險！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"<color=#ffd34c>히힛, 침식체 소멸.</color>","JPN":"<color=#ffd34c>ひひっ。侵食体消滅。</color>","ENG":"<color=#ffd34c>Hehe. C.O. annihilated.</color>","TWN":"<color=#ffd34c>嘻嘻，侵蝕體殲滅。</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"<color=#ffd34c>으, 응! 잘했어 드레카!</color>","JPN":"<color=#ffd34c>う、うん！　やったね、ドレカ！</color>","ENG":"<color=#ffd34c>Y-yeah. Good job, Dreka!</color>","TWN":"<color=#ffd34c>嗯，嗯！幹得好，德蕾卡！</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사, 살았다…!","JPN":"た、助かった……！","ENG":"Th-that was close...!","TWN":"得救了……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아저씨, 괜찮으세요?","JPN":"おじさん、大丈夫ですか？","ENG":"Are you okay, Boris?","TWN":"大叔，你沒事吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"<color=#ffd34c>모두 괜찮아? 다치진 않았니?</color>","JPN":"<color=#ffd34c>みんな大丈夫？　怪我はない？</color>","ENG":"<color=#ffd34c>Is everyone okay? Is anyone hurt?</color>","TWN":"<color=#ffd34c>大家沒事吧？有沒有受傷？</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너희들은… 누구야…?","JPN":"あなたたちは……誰……？","ENG":"Who... are you two...?","TWN":"你們是……誰……？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"만나서 반가워. 내 이름은 드레카바크. 그리고 이쪽은….","JPN":"会えて嬉しいな。私はドレカバク。そしてこっちは……","ENG":"Nice to meet you. I'm Drekavac. And this is...","TWN":"很高興見到你，我叫德蕾卡娃克。這位是……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"에, 에바라고 해. 그, 그러니까… 잘 부탁해…!","JPN":"え、エヴァです。そ、その……よろしく……！","ENG":"I-I'm Eva. U-um... Pleased to meet you...!","TWN":"我，我叫耶娃。那，那個……請多關照……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그 모습, 설마 마브카랑 같은…","JPN":"その姿……まさかマブカと同じ……","ENG":"Wait... are you also a–","TWN":"看你的樣子，難道和瑪卡一樣……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"우린 북방합의체의 <color=#ffd34c>마트료시카 인형</color>이야.","JPN":"私たちは北方合意体の<color=#ffd34c>マトリョシカ人形</color>だよ。","ENG":"We are the Northern Union's <color=#ffd34c>Matryoshka Dolls</color>.","TWN":"我們是北方和議會的<color=#ffd34c>俄羅斯娃娃</color>。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이곳에 생긴 침식현상을 해결하려고 왔어.","JPN":"この村の侵食現象を解決するために来たの。","ENG":"We're here to resolve the Counterside Effect that occurred here.","TWN":"來這裡解決發生的侵蝕現象。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저기 있는 언니도 우리랑 같은 인형인 것 같네?","JPN":"そこの姉さんも私たちと同じ人形みたいね。","ENG":"Looks like that girl over there is also a doll like us.","TWN":"那邊的姊姊好像也是和我們一樣的娃娃呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 새로운 친구를 찾은것 같아 기뻐.","JPN":"へへっ、新しいお友だちが見つかってとっても嬉しいな。","ENG":"Hehe, I'm glad I found a new friend.","TWN":"嘻嘻，找到新朋友真開心。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"마트료시카 인형…!","JPN":"マトリョシカ人形……！","ENG":"Matryoshka Dolls...!","TWN":"俄羅斯娃娃……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"너희들은 포스터에서 봤던 녀석들이군.","JPN":"お前らがポスターのやつらだな。","ENG":"You're the girls from the poster.","TWN":"你們就是在海報上看到的那些傢伙。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"북방군이 여기까진 무슨 일이지?","JPN":"北方軍はこんなところに何の用だ？","ENG":"What business does the Northern Army have here?","TWN":"北方軍怎麼會到這裡來？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"너희들이 우리 마을에 호의를 베풀 이유 따윈 없을 텐데?","JPN":"お前らがこの村のために何かをしてくれることなんて、ないはずだが？","ENG":"I'm certain there is no reason for you to be protecting our village.","TWN":"你們沒有理由對我們村子伸出援手吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그럴리가. 우린 북방합의체의 모든 영토를 지키기 위해 왔는데?","JPN":"そんな。私たちは北方合意体の全領土を守るためにここに来たんだよ？","ENG":"Nonsense. We're here to defend all of the Northern Union's lands.","TWN":"怎麼可能，我們是為了保護北方和議會的所有領土而來的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이번 침식현상은 북방합의체 영토 곳곳에서 일어나고 있는 기현상이야.","JPN":"今回の侵食現象は、北方合意体の領土あちこちで起きてる怪奇現象なの。","ENG":"This Counterside Effect is a weird phenomenon that's been happening all across the Northern Union.","TWN":"這次的侵蝕現象是北方和議會各地普遍發生的奇怪現象。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"조금만 늦었어도 모두 큰일났을 거야.","JPN":"少しでも来るのが遅かったら大変なことになってたと思うよ。","ENG":"If we were just a little bit late, it would've been a disaster here.","TWN":"再晚一點大家就都完蛋了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"의도야 어떻게 됐든 북방군들은 절대로 믿을 수 없어.","JPN":"意図はともあれ、北方軍は信用できない。","ENG":"Whatever your intentions are, we don't trust anyone from the Northern Army.","TWN":"不管出於什麼目的，我們不信任北方軍。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"마을을 구하기 위해서 왔다고? 헛소리!","JPN":"村を助けるためだと？　ほざけ！","ENG":"You're here to save us? Bull crap!","TWN":"說是為了拯救村子來的？胡說八道！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"분명 더러운 속내를 감추고 왔겠지. 썩 꺼져라!","JPN":"腹に何か隠してるんだろう。とっとと失せろ！","ENG":"I'm sure you have an ulterior motive. Now, get out of here!","TWN":"肯定是帶著什麼骯髒的目的，滾開！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐응~?","JPN":"ふうん～","ENG":"Hmm?","TWN":"嗯～？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드드드, 드레카…!","JPN":"ドドド、ドレカ……！","ENG":"D-D-Dreka...!","TWN":"德德德，德蕾卡……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아차차, 이럴때는 메뉴얼을 봐야했지? 이번엔 잘 기억했어 언니.","JPN":"そうだそうだ、こういうときはマニュアルを参考にするんだったね。忘れてないよ、姉さん。","ENG":"Oh, right. I'm supposed to look at the manual in situations like this. I memorized the whole thing, so don't worry, sis.","TWN":"哎呀呀，這時候應該看手冊吧？我這次記得很清楚呢，姊姊。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어디보자… 까칠한 사람이 화를 낼 때는?","JPN":"どれどれ……ぶっきらぼうな人が怒った時は？","ENG":"Let's see here... When a curt person is angry...","TWN":"讓我看看……脾氣暴躁的人發火時？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L3_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"음… 상대방의 기분을 헤아려 주면서 차분하게 대화로 풀어나가기!","JPN":"ふーん……相手の機嫌を取り、落ち着いて会話をする！","ENG":"Hmm... I should try to understand their feelings and calmly resolve the matter through conversation!","TWN":"嗯……體諒對方的情緒，冷靜地透過對話解決！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"뭐, 뭐하는거냐?","JPN":"な、何の真似だ？","ENG":"W-what are you doing?","TWN":"你，你在做什麼？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"뭐하냐고? 그야…","JPN":"何って、それはもちろん…","ENG":"What am I doing? I'm just–","TWN":"我在做什麼？我只是……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"저, 저희는 정말 이 마을의 침식현상을 조사하러 온 것뿐이에요.","JPN":"わ、私たちは本当に、この村の侵食現象を調べに来ただけなんです。","ENG":"W-we're really just here to investigate the Counterside Effect happening in this village.","TWN":"我，我們真的只是來調查這個村子的侵蝕現象的！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"최근 나타나는 기현상은 저희 쪽에서도 조사하고 있었거든요.","JPN":"最近起きてる怪奇現象について、私たちの方からも調査を進めてたので。","ENG":"We have also been conducting investigations on the recent strange phenomenon.","TWN":"我們這邊也在調查最近出現的奇怪現象。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"나, 나머지는 북방군들이 모두 오면 자세히 설명드릴게요!","JPN":"く、詳しいことは北方軍が到着したら話します！","ENG":"W-we'll explain in further in detail once the rest of the Northern Army troops arrive!","TWN":"其，其他的可以等北方軍都到齊了再詳細說明！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니는 정말 말을 잘하는구나. 내 말을 끊을 정도로….","JPN":"姉さんは本当に話が上手だね。私の話を遮るぐらい……","ENG":"You're such a natural at talking, sis. So much so that you even interrupted me...","TWN":"姊姊還真會說話，竟然打斷我的話……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히익! 나, 난 그냥 드레카가 곤란해하는 것 같아서…!","JPN":"ひいっ！　わ、私はただ、ドレカが困ってるのかと思って……！","ENG":"Eek! I-I just thought that you needed some help...!","TWN":"嗚！我，我只是覺得德蕾卡好像很為難……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"고마워 언니. 드레카가 곤란해하는 것도 잘 알아주고….","JPN":"ありがとう、姉さん。ドレカが困ってることにも気づいてくれて。","ENG":"Thanks, sis, for knowing when to step in and help Dreka out.","TWN":"謝謝你，姊姊。能夠體諒德蕾卡的難處……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 이제 돌아가자. 늦으면 군인 아저씨들이 화낼지도 몰라.","JPN":"そろそろ帰ろう。遅くなったら軍人さんたちに怒られるかもしれないよ。","ENG":"Let's go back now. We might get scolded by the soldiers if we're late.","TWN":"那我們現在回去吧，再晚的話，士兵叔叔們可能會生氣喔。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L21_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아, 아아아아… 난 그저….","JPN":"あ、ああああ……私はただ……","ENG":"A-ahhhh... I just...","TWN":"啊，啊啊啊……我只是……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드, 드레카! 잠깐만…!","JPN":"ド、ドレカ！　待って……！","ENG":"D-Dreka! Wait for me...!","TWN":"德，德蕾卡！等等……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L24_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"갑자기 이게 무슨 일이냐… 너무 혼란스럽군.","JPN":"何が起きたんだ……頭が追いつかないな。","ENG":"What was that all about...? I'm so confused.","TWN":"這到底是怎麼回事…好混亂。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤. 괜찮아?","JPN":"サシャ、大丈夫？","ENG":"Sasha? Are you okay?","TWN":"莎夏，你沒事吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응… 그냥 북방군들이 들어온다는 게 좀 걱정되어서.","JPN":"うん……北方軍が来るって言うからちょっと心配になって。","ENG":"Yeah... I'm just concerned about the Northern Army coming here.","TWN":"嗯…只是有點擔心北方軍會進來。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나도 마찬가지야.","JPN":"それは……私も。","ENG":"Same here.","TWN":"我也是。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그리고 저 두 녀석. 나와 같은 인형이라니…!","JPN":"あと、あの二人……私と同じ人形だった……！","ENG":"I can't believe that those two are also Dolls like me...!","TWN":"還有那兩個傢伙，竟然和我一樣是娃娃……！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다른 인형을 보는 건 처음인데….","JPN":"他の人形に会ったのは初めてだ……","ENG":"It's my first time seeing another Doll, but...","TWN":"這是我第一次見到其他的娃娃……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"꺅! 아흑…!","JPN":"きゃっ！　あうっ……！","ENG":"Kyah! Aghh...!","TWN":"呀！啊啊……！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L39_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"큭… 크흑…!","JPN":"くっ……ううっ……！","ENG":"Kgh... Gugh...!","TWN":"呃……嗚嗚……！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L40_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아, 아파… 너무 아파….","JPN":"い、痛い……痛いよ……","ENG":"I-It hurts... so much...","TWN":"好痛……真的好痛……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"부, 부탁이야… 이제 때, 때리지 말아줘….","JPN":"お願い……も、もう殴らないで……","ENG":"P-please... s-stop hitting me...","TWN":"拜，拜託你……別，別再打我了……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"너무해… 나도 아저씨한테 잘 설명할 수 있었는데….","JPN":"ひどい……私だって、おじさんにちゃんと説明できたのに……","ENG":"That was uncalled for... You know I could've explained to that old man too...","TWN":"姊姊好太過分……我明明也可以好好跟叔叔解釋的……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아까 아저씨가 나한테 엄청 화냈어. 웃으며 얘기했는데도 날 싫어했었어.","JPN":"さっきのおじさんすごく怒ってた。笑顔で話したのに、私を敵視してた。","ENG":"He seemed angry at me, and he still hated me even after I smiled and explained the situation.","TWN":"剛才叔叔對我發了很大的火。我明明笑笑地跟他說話，但他還是討厭我。"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니는 내가 못 미더운 거지? 내가 또 사고 칠까 봐 그런거야?","JPN":"姉さんは私が信じられないんでしょ？　私がまたやらかすかもって思ってるんだ。","ENG":"You think I can't do it, right, sis? You think I'm going to cause another commotion?","TWN":"姊姊是不信任我吧？是怕我又闖禍吧？"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"난 그, 그저… 내가 언니로서…!","JPN":"私はただ……あ、姉として……！","ENG":"I-I was just... looking out for you as your older sister...!","TWN":"我只是……作為姊姊……！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"꺅!","JPN":"きゃっ！","ENG":"Kyaaak!","TWN":"嗚！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L47_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아팟!","JPN":"痛いっ！","ENG":"Oww!","TWN":"好痛！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L48_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"미, 미안해… 내가 잘못했어… 다음엔 드레카도 잘 말할 수 있을 거야.","JPN":"ご、ごめんなさい……私が悪かった……次はきっとドレカもちゃんと話せるよ。","ENG":"I-I'm sorry... It's all my fault... I won't cut you off next time, Dreka.","TWN":"對，對不起……是我的錯……下次我不會打斷德蕾卡了。"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이상해. 소중한 사람이 상처입으면 슬퍼진다고 했는데, 하나도 슬프지 않잖아.","JPN":"変なの。大切な人が傷つくと悲しくなるって聞いたのに。全然悲しくない。","ENG":"That's odd. You said that people get sad when their loved ones are hurting. But I'm not sad at all.","TWN":"奇怪，為什麼說重要的人受傷會難過，但我一點也不難過。"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"거짓말쟁이… 언니는 나한테 거짓말을 한거야?","JPN":"嘘つき……姉さん、私に嘘ついたの？","ENG":"Liar... Were you lying to me, sis?","TWN":"騙子……姊姊，你騙我嗎？"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아, 아냣… 꺅!","JPN":"ち、違う……きゃっ！","ENG":"N-no– Kyaah!","TWN":"我，我沒有……啊！"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L2_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그러니까… 드, 드레카는 날 때릴 때 살살 해주니까 그….","JPN":"そ、その……ド、ドレカは私を殴る時、加減してくれるから……","ENG":"B-but... D-Dreka, you're going easy on me because you care...","TWN":"那，那個……德，德蕾卡打我的時候很輕……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"내, 내가 부서질까 봐 소중히 대해주는 거야… 내, 내가 상처 입을까봐….","JPN":"わ、私が壊れないように、大事にしてくれるの……わ、私が傷つかないように……","ENG":"You think I'll break if you hit me too hard... that I might get hurt...","TWN":"是怕我會壞掉……怕我受傷……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"음… 정말?","JPN":"ふーん……本当？","ENG":"Mm... really?","TWN":"嗯……真的？"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"으, 응! 정말이야….","JPN":"う、うん！　本当……","ENG":"Y-yes! Really...","TWN":"嗯，嗯！真的……"},"stage":{"bg":"MAVKA_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"역시… 언니가 최고야.","JPN":"やっぱり……姉さんしかいないね。","ENG":"I knew it... You're the best, sis.","TWN":"果然……姊姊最好了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니는 드레카의 가장 소중한 사람….","JPN":"姉さんは、ドレカのいちばん大切な人……","ENG":"You're my most precious person...","TWN":"姊姊是德蕾卡最重要的人……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니… 앞으로도 꼭 내 곁에 있어 줘. 알았지?","JPN":"姉さん……これからも私のそばにいてよね。ね？","ENG":"Sis... promise you'll always be next to me, okay?","TWN":"姊姊……以後也一定要在我身邊。知道嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"흑흑흑… 알았어….","JPN":"ううっ……わかった……","ENG":"*Sniffle* I-I promise...","TWN":"嗚嗚嗚……知道了……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"어, 어디 가는 거야?","JPN":"えっ……ど、どこに行くの？","ENG":"W-where are you going?","TWN":"你，你要去哪裡？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"마을을 좀 둘러보고 싶어. 오랜만에 사람들을 만날 생각에 너무 설레.","JPN":"村をちょっと回ってみたいの。久しぶりに人に会えると思うとドキドキする。","ENG":"I'm going to check out the village. It's been so long since I've met people! I'm so excited.","TWN":"我想到這個村子四處走走，好久沒見到人了，一想到就很興奮呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"후훗, 아까 봤던 그 두 명… 꼭 친해지고 싶다.","JPN":"ふふっ、さっきの二人……仲よくなりたいな。","ENG":"Haha, I really want to become friends with... the two girls we met earlier.","TWN":"嘻嘻，剛才看到的那兩個人……真想和她們成為朋友。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L18_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드, 드레카… 혼자 가면 안 돼…!","JPN":"ド、ドレカ……！　一人で行っちゃだめだよ……！","ENG":"D-Dreka... you shouldn't go out on your own...!","TWN":"德，德蕾卡……不能一個人去……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};